import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export default function Navbar() {
  const { user } = useAuth();

  return (
    <div className="top-navbar">
      <div style={{ display: 'flex', alignItems: 'center', gap: '32px' }}>
        <Link to="/" className="navbar-brand">
          <img src="/logo.png" alt="Resolve IT Logo" className="navbar-logo" />
          <h2>Resolve IT</h2>
        </Link>
        <nav style={{ display: 'flex', gap: '24px' }}>
          <Link to="/about" style={{ color: 'var(--text-muted)', fontWeight: 600, transition: 'color 0.2s', textDecoration: 'none' }} onMouseEnter={(e) => e.target.style.color = 'var(--primary)'} onMouseLeave={(e) => e.target.style.color = 'var(--text-muted)'}>About Us</Link>
        </nav>
      </div>

      {user && (
        <div className="navbar-user">
          <div className="user-info">
            <span className="user-name">{user.name}</span>
            <span className="user-role">
              <span className="dot" /> {user.role}
            </span>
          </div>
        </div>
      )}
    </div>
  );
}
